import json, urllib.request

vulns=json.load(open("/tmp/vulns.json"))

def getvuln(vid):
    return json.loads(urllib.request.urlopen("https://api.osv.dev/v1/vulns/"+vid, timeout=30).read())

for g,a,v,ids in vulns:
    name=f"{g}:{a}"
    print(f"\n===== {name}:{v} =====")
    for vid in ids:
        d=getvuln(vid)
        summary=d.get("summary","")
        # find affected entry for this package
        fixed_versions=set(); introduced=set(); last_affected=set()
        for aff in d.get("affected",[]):
            pkg=aff.get("package",{})
            if pkg.get("name")==name and pkg.get("ecosystem")=="Maven":
                for r in aff.get("ranges",[]):
                    for ev in r.get("events",[]):
                        if "fixed" in ev: fixed_versions.add(ev["fixed"])
                        if "introduced" in ev: introduced.add(ev["introduced"])
                        if "last_affected" in ev: last_affected.add(ev["last_affected"])
        print(f"  {vid}: fixed={sorted(fixed_versions)} last_affected={sorted(last_affected)} | {summary[:70]}")
